+package doodlin.greeting.aggregator.business.application.greeting.candidate.payload.command
+
+import doodlin.greeting.aggregator.business.application.greeting.candidate.payload.application.constant.ApplicantCustomAttributeAnswerType
+import io.kotest.core.spec.style.BehaviorSpec
+import org.junit.jupiter.api.assertDoesNotThrow
+import org.junit.jupiter.api.assertThrows
+
+class DocumentCustomAttributeAnswerEditCommandTest : BehaviorSpec({
+
+    given("type이 DIRECTLY_FILE이 아닐 때") {
+        `when`("applicationFormAttributeId가 null이면") {
+            then("예외가 발생한다") {
+                assertThrows<IllegalArgumentException> {
+                    DocumentCustomAttributeAnswerEditCommand(
+                        id = null,
+                        applicationFormAttributeId = null,
+                        customName = null,
+                        type = ApplicantCustomAttributeAnswerType.CUSTOM_SHORT_ANSWER,
+                        optionId = null,
+                        text = "답변",
+                        file = null,
+                        period = null,
+                    )
+                }
+            }
+        }
+
+        `when`("applicationFormAttributeId가 있으면") {
+            then("정상 생성된다") {
+                assertDoesNotThrow {
+                    DocumentCustomAttributeAnswerEditCommand(
+                        id = null,
+                        applicationFormAttributeId = 1L,
+                        customName = null,
+                        type = ApplicantCustomAttributeAnswerType.CUSTOM_SHORT_ANSWER,
+                        optionId = null,
+                        text = "답변",
+                        file = null,
+                        period = null,
+                    )
+                }
+            }
+        }
+    }
+
+    given("type이 DIRECTLY_FILE일 때") {
+        `when`("customName이 null이면") {
+            then("예외가 발생한다") {
+                assertThrows<IllegalArgumentException> {
+                    DocumentCustomAttributeAnswerEditCommand(
+                        id = null,
+                        applicationFormAttributeId = null,
+                        customName = null,
+                        type = ApplicantCustomAttributeAnswerType.DIRECTLY_FILE,
+                        optionId = null,
+                        text = null,
+                        file = null,
+                        period = null,
+                    )
+                }
+            }
+        }
+
+        `when`("customName이 빈값이면") {
+            then("예외가 발생한다") {
+                assertThrows<IllegalArgumentException> {
+                    DocumentCustomAttributeAnswerEditCommand(
+                        id = null,
+                        applicationFormAttributeId = null,
+                        customName = "",
+                        type = ApplicantCustomAttributeAnswerType.DIRECTLY_FILE,
+                        optionId = null,
+                        text = null,
+                        file = null,
+                        period = null,
+                    )
+                }
+            }
+        }
+
+        `when`("customName이 공백이면") {
+            then("예외가 발생한다") {
+                assertThrows<IllegalArgumentException> {
+                    DocumentCustomAttributeAnswerEditCommand(
+                        id = null,
+                        applicationFormAttributeId = null,
+                        customName = "   ",
+                        type = ApplicantCustomAttributeAnswerType.DIRECTLY_FILE,
+                        optionId = null,
+                        text = null,
+                        file = null,
+                        period = null,
+                    )
+                }
+            }
+        }
+
+        `when`("customName이 있으면") {
+            then("정상 생성된다") {
+                assertDoesNotThrow {
+                    DocumentCustomAttributeAnswerEditCommand(
+                        id = null,
+                        applicationFormAttributeId = null,
+                        customName = "직접 첨부 파일",
+                        type = ApplicantCustomAttributeAnswerType.DIRECTLY_FILE,
+                        optionId = null,
+                        text = null,
+                        file = null,
+                        period = null,
+                    )
+                }
+            }
+        }
+    }
+})
